CREATE TABLE vulnerabilities_to_tasks
(
	id serial,
	vulnerability_id integer NOT NULL,
	task_id integer NOT NULL,

	CONSTRAINT pk_vulnerabilities_to_tasks PRIMARY KEY (id)
	, CONSTRAINT fk_vulnerabilities_to_tasks_to_vulnerability FOREIGN KEY (vulnerability_id) REFERENCES vulnerabilities (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_vulnerabilities_to_tasks_to_task FOREIGN KEY (task_id) REFERENCES tasks (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_vulnerabilities_to_tasks_vulnerability ON vulnerabilities_to_tasks (vulnerability_id);
CREATE INDEX i_vulnerabilities_to_tasks_task ON vulnerabilities_to_tasks (task_id);
